Context:
The current handler at list-tabs.ts:19 is a one-liner:
```typescript
handler: async (_args, state) => dispatchToExtension(state, 'browser.listTabs', {}),
```
`dispatchToExtension` calls `resolveConnection` which, with no tabId in params, falls back to `getAnyConnection(state)` at extension-protocol.ts:162. This returns whichever connection is first in the Map iterator.

On the extension side, `handleBrowserListTabs` (browser-commands/tab-commands.ts:4-18) calls `chrome.tabs.query({})` which returns only that profile's tabs. So the fix must dispatch to ALL connections.

Changes:
1. Import `dispatchToAllConnections` (a new helper — see below) or iterate connections manually.

2. Add a helper function in extension-protocol.ts:
```typescript
export const dispatchToAllConnections = async (
  state: ServerState,
  method: string,
  params: Record<string, unknown>,
  options?: DispatchOptions,
): Promise<{ connectionId: string; result: unknown }[]> => {
  if (state.extensionConnections.size === 0) {
    throw new Error('Extension not connected');
  }
  const results: { connectionId: string; result: unknown }[] = [];
  // Dispatch to each connection in parallel
  const entries = Array.from(state.extensionConnections.values());
  const settled = await Promise.allSettled(
    entries.map(async conn => {
      const id = getNextRequestId();
      const msg = { jsonrpc: '2.0' as const, method, params: { ...params, __opentabs_dispatchId: id }, id };
      // Create pending dispatch and send
      return new Promise<unknown>((resolve, reject) => {
        const timeoutMs = typeof options === 'object' ? options.timeoutMs ?? DISPATCH_TIMEOUT_MS : DISPATCH_TIMEOUT_MS;
        const timerId = setTimeout(() => {
          state.pendingDispatches.delete(id);
          reject(new Error(`Dispatch ${method} timed out`));
        }, timeoutMs);
        state.pendingDispatches.set(id, {
          resolve, reject, label: method, startTs: Date.now(), timerId,
          connectionId: conn.connectionId,
        });
        try { conn.ws.send(JSON.stringify(msg)); }
        catch (err) { clearTimeout(timerId); state.pendingDispatches.delete(id); reject(err); }
      });
    }),
  );
  for (let i = 0; i < settled.length; i++) {
    const s = settled[i];
    if (s.status === 'fulfilled') {
      results.push({ connectionId: entries[i].connectionId, result: s.value });
    }
  }
  return results;
};
```

3. Rewrite list-tabs.ts handler:
```typescript
handler: async (_args, state) => {
  const responses = await dispatchToAllConnections(state, 'browser.listTabs', {});
  // Each response.result is an array of { id, title, url, active, windowId }
  const allTabs: Array<Record<string, unknown>> = [];
  for (const { connectionId, result } of responses) {
    const tabs = Array.isArray(result) ? result : [];
    for (const tab of tabs) {
      allTabs.push({ ...tab, connectionId });
    }
  }
  return allTabs;
},
```

